class Solution:
    def isRationalEqual(self, s: str, t: str) -> bool:
        def convert(s):
            integer_part = ''
            non_repeating_part = ''
            repeating_part = ''
            has_decimal = False
            for char in s:
                if char == '.':
                    has_decimal = True
                elif char == '(':
                    non_repeating_part = s[s.index(char) + 1:s.index(')')]
                    repeating_part = s[s.index('(') + 1:s.index(')')]
                    break
                else:
                    if not has_decimal:
                        integer_part += char
                    else:
                        non_repeating_part += char
            if not non_repeating_part and not repeating_part:
                return float(integer_part) if integer_part else 0.0
            elif not repeating_part:
                return float(integer_part + '.' + non_repeating_part)
            else:
                return float(integer_part + '.' + non_repeating_part + '(' + repeating_part + ')')

        return convert(s) == convert(t)
